// Import necessary modules
const cron = require('node-cron');
const mongoose = require('mongoose');
const { Task, NotificationLog } = require('./models'); // Assuming Task and NotificationLog models are defined in models.js
const { sendTelegramNotification } = require('./notificationService'); // Function to send notification via Telegram

/**
 * Scheduling Engine to trigger tasks based on their schedule
 */
class SchedulingEngine {
  constructor() {
    this.scheduleTasks();
  }

  /** 
   * Schedule tasks using cron based on defined intervals
   */
  scheduleTasks() {
    // Fetch all active tasks from the database
    Task.find({ status: 'active' }).then(tasks => {
      tasks.forEach(task => {
        // Assuming recurrence object includes type and time
        const { recurrence } = task;
        const cronTime = this.getCronTime(recurrence);

        // Create a cron job for each task
        cron.schedule(cronTime, () => this.handleTask(task), { timezone: 'UTC' });
      });
    });
  }

  /**
   * Get the corresponding cron time for the task based on its recurrence
   * @param {Object} recurrence - Recurrence object containing schedule type and time
   * @returns {String} cronTime - Cron formatted string
   */
  getCronTime(recurrence) {
    if (recurrence.type === 'daily') {
      // Return cron format for daily
      return `0 ${recurrence.time.split(':')[1]} ${recurrence.time.split(':')[0]} * *`;
    } else if (recurrence.type === 'weekly') {
      return `0 ${recurrence.time.split(':')[1]} ${recurrence.time.split(':')[0]} * * ${recurrence.daysOfWeek.join(',`)}`;
    }
    // Custom case can be implemented here
    return '';
  }

  /**
   * Handle the task execution and notification
   * @param {Object} task - The task object related to the job
   */
  handleTask(task) {
    const assigneeId = this.getNextAssignee(task);
    if (!assigneeId) {
      console.error(`No available assignee for task ${task.id}`);
      return;
    }

    sendTelegramNotification(assigneeId, task).then(() => {
      // Log successful notification
      NotificationLog.create({
        taskId: task.id,
        sentAt: new Date(),
        status: 'success',
        retryCount: 0
      });
    }).catch(error => {
      console.error(`Failed to send notification for task ${task.id}:`, error);
      NotificationLog.create({
        taskId: task.id,
        sentAt: new Date(),
        status: 'failed',
        errorDetails: error.message,
        retryCount: 1 // This could increment based on your retry logic
      });
    });
  }

  /**
   * Get the next available assignee based on rotation index
   * @param {Object} task - The task object
   * @returns {String|null} - Returns the ID of the next assignee or null if none are available
   */
  getNextAssignee(task) {
    let index = task.rotationIndex;
    const userList = task.assignees.filter(assignee => !task.unavailableMembers.includes(assignee));

    if (userList.length === 0) return null; // No available users

    const assigneeId = userList[index];
    task.rotationIndex = (index + 1) % userList.length; // Update rotation index
    return assigneeId;
  }
}

// Initialize the scheduling engine
new SchedulingEngine();
